protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // [EF9 Breaking] HasIndex now throws for Cosmos entities — removed.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep).

    modelBuilder.Entity<Product>().ToContainer("Products");

    // [EF9 Breaking] Default discriminator property renamed from "Discriminator" to "$type".
    // Existing 500K documents use "Discriminator", and direct SQL queries reference it.
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // [EF9 Breaking] id values no longer include the discriminator prefix.
    // EF8 wrote "Product|123"; EF9 writes "123". Preserve the old format so
    // FindAsync and point-reads still match existing documents.
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

